1. Create a new file called `index.js` in your project directory and add the following code:
```javascript
const { Client, Intents } = require('discord.js');
const { Command } = require('discord.js-commando');

const client = new Client({ intents: [Intents.FLAGS.GUILD_MEMBERS] });

client.once('ready', () => {
  console.log('Ready!');
});

client.once('interactionCreate', async (interaction) => {
  if (!interaction.isCommand()) return;

  const { command } = interaction;

  if (command.name === 'ban') {
    const { options } = interaction;

    const member = options.get('member')?.member;
    const reason = options.get('reason')?.value;

    if (!member) {
      await interaction.reply({ content: 'Please provide a member to ban.', ephemeral: true });
      return;
    }

    if (!reason) {
      await interaction.reply({ content: 'Please provide a reason for the ban.', ephemeral: true });
      return;
    }

    try {
      await member.ban({ reason });
      await interaction.reply({ content: `Banned ${member.user.tag} for ${reason}.`, ephemeral: true });
