#include <iostream>
#include <string>
#include <pandoc/pandoc.hpp>

std::string markdownToHtml(const std::string& markdown) {
    pandoc::Document doc;
    doc.setFormat("html");
    doc.setInputFormat("markdown");
    doc.setInputString(markdown);
    doc.setOutputString("");
    doc.convert();
    return doc.getOutputString();
}

int main() {
    std::string markdown = "# Hello, world!\n\nThis is a **markdown** document.\n\nIt contains some *italic* and **bold** text.\n\nThere is also a [link](https://example.com).";
    std::string html = markdownToHtml(markdown);
    std::cout << html << std::endl;
    return 0;
}
```
